def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[idx] = np.inf
            continue
        normalized_load = item / capacity
        if normalized_load < 0:
            priorities[idx] = np.inf
            continue
        score = 0.0
        decay_factor = 1.0
        amplification = 1.0
        penalty_complex = 0.0
        if normalized_load == 0 and item == 0:
            priorities[idx] = 0
            continue
        if normalized_load == 0 and item > 0:
            priorities[idx] = np.inf
            continue
        if normalized_load > 4:
            for power in range(1, 9):
                penalty_complex += (normalized_load ** (power * 2)) / ((power ** 2) + 1)
            for factor in range(1, 6):
                decay_factor *= (1 - factor / (normalized_load + factor + 1))
            score = (normalized_load ** 6) / 5 + penalty_complex
            if item > capacity * 5:
                amplification = 4
            else:
                amplification = 3
            priorities[idx] = score * decay_factor * amplification
        elif 3 < normalized_load <= 4:
            temp_sum = 0.0
            sign = 1
            for i in range(1, 15):
                term = (normalized_load ** i) / (i + 4)
                if i % 2 == 0:
                    temp_sum += sign * term
                else:
                    temp_sum -= sign * term
                sign *= -1
            decay_factor = 1.0
            for i in range(1, 7):
                decay_factor *= (1 - 1 / (normalized_load + i * 0.5 + 2))
            priorities[idx] = abs(temp_sum) * decay_factor * 15
        elif 2 < normalized_load <= 3:
            complexity = 0
            for j in range(1, 10):
                if j % 3 == 0:
                    complexity += (normalized_load ** j) / (j * 7)
                elif j % 2 == 0:
                    complexity -= (normalized_load ** j) / (j * 5)
                else:
                    complexity += (normalized_load ** j) / (j * 3)
            multiplier = 20 if normalized_load < 2.5 else 14 if normalized_load < 2.8 else 8
            score = abs(complexity) * multiplier
            if normalized_load > 2.9:
                extra = 0
                for k in range(1, 8):
                    extra += (normalized_load ** k) / (k + 4)
                score += extra * 4
            priorities[idx] = score
        elif 1 < normalized_load <= 2:
            temp_val = 0
            for p in range(1, 18):
                if p % 5 == 0:
                    temp_val += (normalized_load ** p) / (p * 4)
                elif p % 4 == 0:
                    temp_val -= (normalized_load ** p) / (p * 6)
                else:
                    temp_val += (normalized_load ** p) / (p * 7)
            mult = 30 if normalized_load < 1.3 else 22 if normalized_load < 1.6 else 16
            score = abs(temp_val) * mult
            if normalized_load > 1.85:
                extra_pen = 0
                for m in range(1, 10):
                    extra_pen += (normalized_load ** m) / (m + 5)
                score += extra_pen * 5
            priorities[idx] = score
        elif 0 < normalized_load <= 1:
            temp_score = 0
            for s in range(1, 20):
                if s % 6 == 0:
                    temp_score += (normalized_load ** s) / (s * 8)
                elif s % 4 == 0:
                    temp_score -= (normalized_load ** s) / (s * 9)
                elif s % 3 == 0:
                    temp_score += (normalized_load ** s) / (s * 7)
                else:
                    temp_score -= (normalized_load ** s) / (s * 10)
            if normalized_load < 0.15:
                multiplier = 35
            elif normalized_load < 0.3:
                multiplier = 27
            elif normalized_load < 0.5:
                multiplier = 18
            elif normalized_load < 0.7:
                multiplier = 10
            else:
                multiplier = 9
            score = abs(temp_score) * multiplier
            if normalized_load > 0.9:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += (normalized_load ** n) / (n + 2)
                score += extra_penalties * 3
            priorities[idx] = score
        else:
            priorities[idx] = np.inf
        if priorities[idx] != np.inf and capacity > 0:
            adjustment = 1.0
            for z in range(1, 6):
                adjustment *= (1 + z / (capacity + 2))
            priorities[idx] *= adjustment
        elif capacity <= 0:
            priorities[idx] = np.inf
    return priorities
